      const warmupSequences={push:["Armsirkler","Skuldermobilitet","Scapula Push-ups","Wall Pushups","Dynamiske bryståpnere"],pull:["Armsirkler","Scapular Retractions","Bird Dog","Thoracic Rotation","Dynamiske skulderbevegelser"],core:["Cat Cow","Bird Dog","Dead Bug","Bekkentilt","Planke med skuldertouch"],fullbody:["Air Squats","Reverse Lunges","Hoftesirkler","Leg Swings","High Knees"],crosstrening:["Jumping Jacks","Air Squats","Wall Pushups","High Knees","Mountain Climbers"],kroppsvekt:["Jumping Jacks","Air Squats","Armsirkler","Reverse Lunges","Mountain Climbers"],tabata:["Jumping Jacks","Air Squats","Wall Pushups","High Knees","Mountain Climbers"],morgen:["Nasal Breathing","Arm Circles","Cat Cow","Glute Bridge","Ankle Rocks"],toying:["Nasal Breathing","Arm Circles","Cat Cow","Hoftesirkler","Standing Forward Fold"],nodokt:["Jumping Jacks","Air Squats","Arm Circles","Glute Bridge","Mountain Climbers"]};
